INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'silbi-self-pay-rate', '실손 자기부담금 — 내가 얼마를 부담할까', '실손보험의 급여·비급여 자기부담 비율과 통원 공제금액의 구조를 세대별로 정리해, 실제 받는 금액을 가늠하도록 돕습니다.', '<p>실손보험은 치료비 전액이 아니라 자기부담금을 뺀 금액을 보장합니다. 자기부담 구조를 알면 실제 받는 금액을 미리 가늠할 수 있습니다.</p>
<h2>급여와 비급여 자기부담</h2>
<ul>
<li>급여 본인부담: 일정 비율(세대에 따라 10~20% 수준)</li>
<li>비급여: 자기부담 비율이 더 높게(예: 30% 수준) 적용되는 경향</li>
</ul>
<h2>통원 공제금액</h2>
<p>통원은 건당 일정 공제금액을 빼고 보장하는 경우가 많습니다. 소액 통원은 공제금액 때문에 실제 지급이 적거나 없을 수 있습니다.</p>
<table>
<thead><tr><th>구분</th><th>경향</th></tr></thead>
<tbody>
<tr><td>급여</td><td>자기부담 낮음</td></tr>
<tr><td>비급여</td><td>자기부담 높음</td></tr>
<tr><td>통원</td><td>건당 공제 적용</td></tr>
</tbody>
</table>
<h2>세대별 차이</h2>
<p>4세대는 급여·비급여를 분리해 자기부담을 다르게 적용하고, 비급여 이용량에 따라 보험료 할인·할증이 있습니다. 내 세대의 자기부담 구조를 확인하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>급여보다 비급여 자기부담이 큼</li><li>통원은 건당 공제 적용</li><li>세대별 구조 확인 필수</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","자기부담금","공제"]', '[{"q":"실손은 치료비를 다 주나요?","a":"아닙니다. 급여·비급여 자기부담과 통원 공제금액을 뺀 금액을 보장합니다."},{"q":"비급여 자기부담이 더 큰가요?","a":"일반적으로 비급여의 자기부담 비율이 급여보다 높게 적용됩니다. 세대에 따라 다릅니다."},{"q":"소액 통원은 왜 안 나오나요?","a":"건당 공제금액보다 작으면 지급액이 없거나 적을 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'silbi-emergency-room', '응급실 이용과 실손 — 비응급으로 가면 손해?', '응급실 진료의 실손 보장과, 비응급 상태로 대형병원 응급실 이용 시 본인부담이 커지는 구조를 정리했습니다.', '<p>응급실 진료비는 실손으로 보장될 수 있지만, 응급인지 비응급인지에 따라 본인부담이 크게 달라집니다.</p>
<h2>응급과 비응급</h2>
<ul>
<li>응급 증상으로 응급실을 이용하면 응급의료 관련 비용이 보장 대상이 될 수 있음</li>
<li>비응급 상태로 상급종합병원 응급실을 이용하면 응급의료관리료 등 본인부담이 커질 수 있음</li>
</ul>
<table>
<thead><tr><th>상황</th><th>본인부담</th></tr></thead>
<tbody>
<tr><td>응급 증상</td><td>상대적으로 경감</td></tr>
<tr><td>비응급+대형병원</td><td>가중될 수 있음</td></tr>
</tbody>
</table>
<h2>실손 보장 관점</h2>
<p>실손은 급여·비급여 본인부담을 보장하지만, 비응급 이용으로 발생한 일부 비용은 보장 범위·자기부담에 따라 달라질 수 있습니다. 진료의 응급성 판단이 핵심입니다.</p>
<h2>팁</h2>
<p>경증이라면 가까운 병·의원을 먼저 이용하는 것이 비용 면에서 유리할 수 있습니다. 응급 상황 판단이 애매하면 응급의료 상담 등을 활용하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>응급·비응급에 따라 본인부담 차이</li><li>비응급+대형병원은 부담 가중</li><li>경증은 가까운 병·의원 우선</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","응급실","응급의료"]', '[{"q":"응급실 진료도 실손이 되나요?","a":"응급의료 관련 비용이 보장 대상이 될 수 있습니다. 다만 응급성·본인부담 구조에 따라 금액이 달라집니다."},{"q":"비응급으로 가면 왜 손해인가요?","a":"비응급 상태로 대형병원 응급실을 이용하면 응급의료관리료 등 본인부담이 커질 수 있습니다."},{"q":"응급 여부가 애매하면요?","a":"응급의료 상담 등을 활용하고, 경증이면 가까운 병·의원을 먼저 이용하는 것이 비용 면에서 유리할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'silbi-oriental-medicine', '한방치료와 실손 — 첩약·약침은 보장될까', '한방치료의 급여·비급여 구분과 실손 보장 한계, 한방 비급여(첩약·약침 등)의 처리 경향을 정리했습니다.', '<p>한의원·한방병원 치료비도 실손으로 받을 수 있을지 궁금해하는 경우가 많습니다. 급여와 비급여를 나눠 보면 이해가 쉽습니다.</p>
<h2>급여 한방</h2>
<ul>
<li>건강보험이 적용되는 급여 한방 진료의 본인부담은 보장 가능성이 있음</li>
</ul>
<h2>비급여 한방</h2>
<ul>
<li>첩약, 약침, 추나(비급여분) 등 한방 비급여는 실손 보장에서 제외되거나 제한되는 경향</li>
</ul>
<table>
<thead><tr><th>구분</th><th>경향</th></tr></thead>
<tbody>
<tr><td>급여 한방</td><td>본인부담 보장 가능</td></tr>
<tr><td>비급여 한방</td><td>보장 제한·제외</td></tr>
</tbody>
</table>
<h2>확인 방법</h2>
<p>한방 치료는 급여·비급여 구분과 가입 세대에 따라 결과가 다릅니다. 영수증의 급여/비급여 항목을 확인하고, 약관의 한방 보장 범위를 점검하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>급여 한방은 보장 가능성</li><li>첩약·약침 등 비급여는 제한</li><li>영수증 급여/비급여 구분 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","한방치료","비급여"]', '[{"q":"한약도 실손으로 받나요?","a":"첩약 등 한방 비급여는 보장에서 제외·제한되는 경향입니다. 급여 한방의 본인부담은 보장될 수 있습니다."},{"q":"추나치료는요?","a":"급여·비급여 구분에 따라 다릅니다. 비급여분은 보장이 제한될 수 있어 영수증과 약관을 확인하세요."},{"q":"세대마다 다른가요?","a":"가입 세대와 특약에 따라 한방 보장 범위가 다를 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('cancer', 'thyroid-cancer-coverage', '갑상선암 보험 보장 — 왜 진단비가 적게 나올까', '갑상선암이 보험에서 유사암(소액)으로 분류되는 이유와, 전이 시 일반암으로 보는 경우 등 보장 포인트를 정리했습니다.', '<p>갑상선암은 발생이 잦지만 보험금이 기대보다 적게 나와 당황하는 경우가 많습니다. 많은 약관에서 유사암(소액)으로 분류하기 때문입니다.</p>
<h2>유사암 분류</h2>
<ul>
<li>갑상선암은 흔히 유사암으로 분류되어 일반암보다 적게 지급</li>
<li>지급 비율은 약관마다 다름</li>
</ul>
<h2>전이된 경우</h2>
<p>갑상선암이 림프절 등으로 전이되어 약관이 정한 일반암 기준에 해당하면, 일반암으로 보아 보장이 달라질 수 있습니다. 진단서의 분류와 코드가 중요합니다.</p>
<table>
<thead><tr><th>구분</th><th>경향</th></tr></thead>
<tbody>
<tr><td>국한된 갑상선암</td><td>유사암(소액)</td></tr>
<tr><td>일반암 기준 충족</td><td>일반암 보장 가능</td></tr>
</tbody>
</table>
<h2>가입·청구 팁</h2>
<p>갑상선암을 대비하려면 유사암 보장 비율을 확인하고, 청구 시 진단서의 분류·코드가 정확히 기재되도록 하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>갑상선암은 보통 유사암(소액)</li><li>전이 등 일반암 기준 충족 시 달라질 수 있음</li><li>진단서 분류·코드 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["암보험","갑상선암","유사암"]', '[{"q":"갑상선암은 왜 진단비가 적나요?","a":"많은 약관이 갑상선암을 유사암(소액)으로 분류하기 때문입니다. 지급 비율은 약관을 확인하세요."},{"q":"전이되면 일반암이 되나요?","a":"약관이 정한 일반암 기준에 해당하면 일반암으로 볼 수 있습니다. 진단서 분류·코드가 중요합니다."},{"q":"갑상선암 대비는 어떻게 하나요?","a":"유사암 보장 비율을 확인하고 필요하면 유사암 보장을 보강하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('cancer', 'cancer-checkup-pet-ct', '암 검사비(PET-CT 등)와 보험 — 진단·추적검사 보장', 'PET-CT 등 고가 암 관련 검사비의 실손·암보험 보장 여부와 의학적 필요성 쟁점을 정리했습니다.', '<p>암 진단과 치료 과정에서는 PET-CT 같은 고가 검사가 필요할 수 있습니다. 검사비 보장은 급여 여부와 의학적 필요성에 따라 달라집니다.</p>
<h2>검사비 보장 관점</h2>
<ul>
<li>암 진단·전이 평가 목적의 검사가 급여로 인정되면 본인부담 보장 가능</li>
<li>비급여로 처리되는 검사는 세대·특약 조건에 따라 보장이 달라짐</li>
</ul>
<table>
<thead><tr><th>구분</th><th>경향</th></tr></thead>
<tbody>
<tr><td>급여 검사</td><td>본인부담 보장</td></tr>
<tr><td>비급여 검사</td><td>특약·한도 적용</td></tr>
</tbody>
</table>
<h2>의학적 필요성</h2>
<p>치료 방침 결정을 위한 필요한 검사인지가 보장 판단의 핵심입니다. 단순 확인·반복 검사는 보장이 제한될 수 있어, 검사의 필요성이 드러나는 소견을 확보하는 것이 좋습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>급여 검사는 본인부담 보장</li><li>비급여는 세대·특약 한도</li><li>의학적 필요성 입증이 관건</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["암보험","PET-CT","검사비"]', '[{"q":"PET-CT도 보험이 되나요?","a":"암 진단·전이 평가 목적으로 급여 처리되면 본인부담이 보장될 수 있습니다. 비급여는 세대·특약에 따라 다릅니다."},{"q":"반복 검사도 보장되나요?","a":"의학적 필요성이 인정되어야 합니다. 단순 확인·반복은 보장이 제한될 수 있습니다."},{"q":"무엇을 준비하면 좋나요?","a":"검사의 필요성이 드러나는 소견·진단 자료를 확보하면 보장 판단에 도움이 됩니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'parking-hit-and-run', '주차 중 물피도주 — 가해자를 못 찾으면 어떻게 보상받을까', '주차된 내 차가 긁히고 가해자가 도주한 경우의 보상 방법과 물피도주 신고 절차를 정리했습니다.', '<p>주차해 둔 차가 긁히거나 찌그러졌는데 가해자를 알 수 없는 경우가 흔합니다. 이때 보상받는 방법을 알아두면 당황하지 않습니다.</p>
<h2>가해자를 못 찾을 때</h2>
<ul>
<li>자기차량손해(자차)에 가입돼 있으면 내 보험으로 수리 가능</li>
<li>자차로 처리하면 자기부담금과 할증 가능성을 함께 고려</li>
</ul>
<h2>물피도주 신고</h2>
<p>주차장 등에서 물적 피해만 입히고 도주(물피도주)한 경우, 블랙박스·CCTV로 가해 차량을 특정해 신고할 수 있습니다. 가해자가 확인되면 상대 보험으로 처리할 수 있습니다.</p>
<table>
<thead><tr><th>상황</th><th>처리</th></tr></thead>
<tbody>
<tr><td>가해자 확인</td><td>상대 보험(대물)</td></tr>
<tr><td>가해자 불명</td><td>자차로 수리</td></tr>
</tbody>
</table>
<h2>팁</h2>
<p>주차 중 충격 감지 블랙박스가 있으면 가해 차량 특정에 유리합니다. 소액 손상은 자차 할증과 수리비를 비교해 처리 방법을 정하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>가해자 불명 시 자차로 수리</li><li>블랙박스·CCTV로 특정해 신고 가능</li><li>소액은 할증 비교 후 결정</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","물피도주","자차"]', '[{"q":"주차하다 긁혔는데 범인을 몰라요.","a":"자차에 가입돼 있으면 내 보험으로 수리할 수 있습니다. 자기부담금·할증을 함께 고려하세요."},{"q":"물피도주 신고하면 잡히나요?","a":"블랙박스·CCTV로 가해 차량을 특정하면 신고를 통해 처리될 수 있습니다."},{"q":"자차로 처리하면 보험료가 오르나요?","a":"사고로 처리되면 할증 요인이 될 수 있습니다. 소액은 수리비와 비교해 결정하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'used-car-insurance-transfer', '중고차 보험 — 명의이전과 경력 승계', '중고차 구매 시 자동차보험 가입 절차와 명의이전, 보험 경력·할인 승계 관련 핵심을 정리했습니다.', '<p>중고차를 사면 명의이전과 함께 자동차보험을 새로 들어야 합니다. 절차와 경력 승계를 알면 공백 없이 처리할 수 있습니다.</p>
<h2>가입 순서</h2>
<ul>
<li>명의이전 전후로 보험 공백이 생기지 않게 가입 시점 조율</li>
<li>운행 전 의무보험(책임보험) 가입은 필수</li>
</ul>
<h2>경력·할인 승계</h2>
<p>본인의 기존 보험 가입 경력(무사고 할인 등)은 새 차에도 이어집니다. 다만 차량 자체의 사고 이력과는 별개입니다. 가족 간 경력 인정 등은 조건을 확인하세요.</p>
<table>
<thead><tr><th>항목</th><th>확인</th></tr></thead>
<tbody>
<tr><td>의무보험</td><td>운행 전 필수 가입</td></tr>
<tr><td>경력 승계</td><td>본인 무사고 할인 유지</td></tr>
</tbody>
</table>
<h2>유의점</h2>
<p>명의이전 지연으로 보험·과태료 문제가 생기지 않도록 일정에 맞춰 처리하고, 차량 상태에 따라 자차 가입 실익을 판단하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>운행 전 의무보험 필수</li><li>본인 가입 경력·할인은 승계</li><li>명의이전 일정과 보험 시점 조율</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","중고차","명의이전"]', '[{"q":"중고차도 보험을 새로 드나요?","a":"네. 명의이전과 함께 본인 명의로 자동차보험에 가입해야 하며, 운행 전 의무보험은 필수입니다."},{"q":"기존 할인은 이어지나요?","a":"본인의 무사고 할인 등 가입 경력은 새 차에도 승계됩니다. 차량의 사고 이력과는 별개입니다."},{"q":"자차는 꼭 들어야 하나요?","a":"선택입니다. 차량 가치와 위험을 고려해 실익을 판단하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'two-wheeler-insurance', '이륜차(오토바이) 보험 — 의무보험과 배달 운행', '오토바이 의무보험과 유상운송(배달) 시 필요한 보장, 가입 시 유의점을 정리했습니다.', '<p>오토바이도 자동차처럼 의무보험 가입 대상입니다. 특히 배달 등 유상운송은 별도의 보장이 필요해 주의가 필요합니다.</p>
<h2>의무보험</h2>
<ul>
<li>이륜차도 책임보험(의무보험) 가입이 필요</li>
<li>미가입 운행은 과태료 등 불이익</li>
</ul>
<h2>유상운송(배달)</h2>
<p>배달처럼 돈을 받고 운행하는 경우, 일반 개인용 보장으로는 사고 시 보장이 제한될 수 있습니다. 유상운송을 보장하는 별도 보험·특약이 필요합니다.</p>
<table>
<thead><tr><th>용도</th><th>보장</th></tr></thead>
<tbody>
<tr><td>개인용</td><td>일반 이륜차 보험</td></tr>
<tr><td>유상운송(배달)</td><td>유상운송 보장 필요</td></tr>
</tbody>
</table>
<h2>유의점</h2>
<p>용도를 사실대로 고지하지 않으면 사고 시 보장이 거절될 수 있습니다. 배달 운행이라면 반드시 해당 보장을 확인하세요. 이륜차는 사고 위험이 커 대인·대물 한도도 충분히 두는 것이 안전합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>이륜차도 의무보험 필수</li><li>배달은 유상운송 보장 필요</li><li>용도 고지·충분한 한도</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","이륜차","배달보험"]', '[{"q":"오토바이도 보험이 의무인가요?","a":"네. 책임보험(의무보험) 가입이 필요하며 미가입 운행은 불이익이 있습니다."},{"q":"배달용도 일반 보험으로 되나요?","a":"유상운송은 일반 개인용 보장으로 제한될 수 있어 유상운송 보장이 별도로 필요합니다."},{"q":"용도를 안 알리면요?","a":"사실과 다르게 고지하면 사고 시 보장이 거절될 수 있습니다. 용도를 정확히 알리세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'medical-records-issuance', '진료기록 발급 — 누가, 어떻게, 무엇을 뗄까', '보험 청구·분쟁에 필요한 진료기록(의무기록) 사본 발급 권한과 절차, 종류를 정리했습니다.', '<p>보험금 청구나 분쟁에서 진료기록(의무기록) 사본이 필요할 때가 있습니다. 발급 권한과 종류를 알면 빠르게 준비할 수 있습니다.</p>
<h2>누가 발급받나</h2>
<ul>
<li>환자 본인</li>
<li>정당하게 위임받은 대리인(위임장·신분 확인 필요)</li>
<li>법령이 정한 경우의 보호자 등</li>
</ul>
<h2>어떤 기록을 뗄까</h2>
<table>
<thead><tr><th>종류</th><th>내용</th></tr></thead>
<tbody>
<tr><td>진료기록부</td><td>경과·처방 등 상세</td></tr>
<tr><td>검사결과지</td><td>영상·병리 등 결과</td></tr>
<tr><td>수술기록지</td><td>수술명·방법</td></tr>
</tbody>
</table>
<h2>발급 팁</h2>
<p>청구 목적에 맞는 기록을 특정해 요청하면 효율적입니다. 발급에는 수수료가 들 수 있고, 분쟁 대비라면 검사결과지·수술기록지처럼 핵심 근거가 되는 기록을 함께 확보하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>본인·정당한 대리인이 발급</li><li>목적에 맞는 기록을 특정</li><li>검사·수술 기록이 핵심 근거</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","진료기록","의무기록"]', '[{"q":"진료기록은 누가 뗄 수 있나요?","a":"환자 본인 또는 정당하게 위임받은 대리인이 신분 확인을 거쳐 발급받을 수 있습니다."},{"q":"어떤 기록이 필요한가요?","a":"청구·분쟁 목적에 맞춰 진료기록부, 검사결과지, 수술기록지 등 핵심 근거를 특정해 발급받으세요."},{"q":"발급 비용이 드나요?","a":"의료기관별 수수료가 발생할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'disease-vs-accident-death', '질병사망과 상해사망 — 사망보험금도 원인이 중요하다', '질병으로 인한 사망과 사고로 인한 상해사망의 보장 차이, 가입 담보에 따른 지급 여부를 정리했습니다.', '<p>사망보험금도 원인에 따라 적용되는 담보가 다릅니다. 질병사망과 상해사망은 가입한 보장에 따라 지급 여부가 갈립니다.</p>
<h2>담보 구분</h2>
<ul>
<li>질병사망: 질병으로 사망 — 종신·정기보험 등 사망보장</li>
<li>상해사망: 사고(외래의 급격·우연)로 사망 — 상해사망 담보</li>
</ul>
<table>
<thead><tr><th>원인</th><th>해당 담보</th></tr></thead>
<tbody>
<tr><td>질병</td><td>일반 사망보장</td></tr>
<tr><td>사고(상해)</td><td>상해사망(추가 지급 가능)</td></tr>
</tbody>
</table>
<h2>중복 지급 가능성</h2>
<p>사고로 사망한 경우, 일반 사망보장과 상해사망 담보를 모두 가입했다면 각각 지급될 수 있습니다. 반대로 상해사망 담보만 있으면 질병사망은 보장되지 않습니다.</p>
<h2>유의점</h2>
<p>원인이 모호하면(질병이 사고를 유발했는지 등) 다툼이 생길 수 있어, 사망진단서의 사인과 경위 자료가 중요합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>질병사망·상해사망은 담보가 다름</li><li>사고사망은 둘 다 지급 가능</li><li>사인·경위 자료가 관건</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","사망보험금","상해사망"]', '[{"q":"상해사망 담보만 있으면 병으로 죽으면 보장이 안 되나요?","a":"상해사망 담보는 사고 사망을 보장합니다. 질병사망은 별도의 사망보장이 있어야 합니다."},{"q":"사고로 죽으면 보험금을 두 배 받나요?","a":"일반 사망보장과 상해사망 담보를 모두 가입했다면 각각 지급될 수 있습니다."},{"q":"사인이 애매하면요?","a":"사망진단서의 사인과 사고 경위 자료가 판단 근거가 됩니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('terms', 'insurance-age-calculation', '보험나이 계산 — 만나이와 다른 이유', '보험료 산정 기준이 되는 보험나이(상령일)의 계산법과, 가입 시점이 보험료에 미치는 영향을 정리했습니다.', '<p>보험 가입 시 적용되는 나이는 우리가 흔히 쓰는 만나이와 다를 수 있습니다. 보험나이를 알면 가입 시점을 유리하게 잡을 수 있습니다.</p>
<h2>보험나이 계산</h2>
<p>일반적으로 보험나이는 계약일 기준으로 직전 생일부터의 경과 기간이 6개월 미만이면 버리고, 6개월 이상이면 한 살을 올려 계산합니다. 즉 만나이와 한 살 차이가 날 수 있습니다.</p>
<h2>상령일</h2>
<p>보험나이가 한 살 올라가는 날을 상령일이라고 합니다. 상령일이 지나면 보험나이가 올라 보험료가 비싸질 수 있습니다.</p>
<table>
<thead><tr><th>시점</th><th>영향</th></tr></thead>
<tbody>
<tr><td>상령일 전</td><td>현재 보험나이로 가입</td></tr>
<tr><td>상령일 후</td><td>한 살 올라 보험료↑ 가능</td></tr>
</tbody>
</table>
<h2>팁</h2>
<p>가입을 고민 중이라면 상령일 전에 가입하는 것이 보험료 면에서 유리할 수 있습니다. 본인의 보험나이와 상령일을 미리 확인하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>보험나이는 만나이와 다를 수 있음</li><li>6개월 기준으로 반올림</li><li>상령일 전 가입이 유리할 수 있음</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부와 제도는 가입하신 상품의 약관·관련 법령과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["약관해설","보험나이","상령일"]', '[{"q":"보험나이가 만나이와 다른가요?","a":"계약일 기준 6개월 미만은 버리고 6개월 이상은 올려 계산해, 만나이와 한 살 차이가 날 수 있습니다."},{"q":"상령일이 무엇인가요?","a":"보험나이가 한 살 올라가는 날입니다. 이 날이 지나면 보험료가 오를 수 있습니다."},{"q":"언제 가입하는 게 유리한가요?","a":"상령일 전에 가입하면 보험나이가 낮아 보험료 면에서 유리할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('whole-life', 'disability-income-protection', '소득보장보험 — 아파서 일 못 할 때의 생활비', '질병·상해로 일하지 못할 때 소득 공백을 보완하는 소득보장(취업불능) 보험의 개념과 확인 포인트를 정리했습니다.', '<p>큰 병이나 사고로 일을 못 하게 되면 치료비뿐 아니라 소득 공백이 큰 문제가 됩니다. 이를 보완하는 것이 소득보장(취업불능) 보험입니다.</p>
